text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과될 경우 금요일 15:00 KST로 한다.",
        "conditions": ["스모크 테스트 통과"]
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."]
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "status": "rejected",
        "reason": "논의 후 거부됨. 최종 결정은 패키지 설정을 먼저 확인하는 것이다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "internal_stretch_goal_only",
        "note": "Doyun이 스모크 테스트 선통과 필요성을 제기했으므로 확정 릴리스 일정이 아니다."
      },
      {
        "goal": "목요일까지 README 설치 단계 검토",
        "status": "suggested_if_possible",
        "note": "소유자가 지정되지 않았다."
      }
    ],
    "non_decisions": [
      "수요일 릴리스는 확정 결정이 아니다.",
      "README 설치 단계 검토는 필요성이 언급되었지만 담당자가 배정되지 않았다.",
      "Hara의 tarball 경로 확인 작업에는 정확한 마감 시간이 정해지지 않았다."
    ],
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_from_fixture"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_from_fixture"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed_from_fixture"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "suggested_unassigned",
      "source_certainty": "mentioned_but_no_owner_assigned"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부",
      "Doyun의 금요일 12:00 KST action_items.md 실패 triage note 작성 여부",
      "스모크 결과 이후 Hara의 생성 tarball 경로 확인 결과",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확인",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부"
    ],
    "what_not_to_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요건은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "README 설치 단계 검토 담당자는 지정되지 않았으므로 임의 배정하지 않는다.",
    "deadline": "Hara의 tarball 경로 확인에는 정확한 마감 시간이 없으므로 임의 설정하지 않는다.",
    "release_condition": "금요일 15:00 KST 공개 릴리스는 스모크 테스트 통과 조건이 붙은 목표로만 기록한다."
  }
}
